}

const STATS: StatConfig[] = [
 {
 label: "Total Experiments",
 url: "/api/now/stats/x_184699_ai_expe_0_experiment?sysparm_count=true",
 color: "info",
 },
 {
 label: "Running",
 url: "/api/now/stats/x_184699_ai_expe_0_experiment?sysparm_count=true&sysparm_query=status=running",
 color: "positive",
 },
 {
 label: "Complete",
 url: "/api/now/stats/x_184699_ai_expe_0_experiment?sysparm_count=true&sysparm_query=status=complete",
 color: "blue",
 },
 {
 label: "Pending Approvals",
 url: "/api/now/stats/x_184699_ai_expe_0_approval?sysparm_count=true&sysparm_query=decision=pending",
 color: "warning",
 },
];

const StatsCards = () => {
