 const [loading, setLoading] = useState(true);

 useEffect(() => {
 const fetchStats = async () => {
 try {
 const results = await Promise.all(
 STATS.map((stat) =>
 fetch(stat.url, {
 headers: {
 Accept: "application/json",
 "X-UserToken": window.g_ck,
 },
 }).then((res) => res.json())
 )
 );
 setCounts(results.map((r) => r.result?.stats?.count || "0"));
 } catch (e) {
