 <Card
 key={stat.label}
 size="md"
 interaction="none"
 sidebar={{ color: stat.color, variant: "primary" }}
 >
 <CardHeader heading={{ label: stat.label, size: "sm" }} />
 <span className="stat-value">{counts[i]}</span>
 </Card>
 ))}
 </div>
 );
};

export default StatsCards;
