import { isEqual, isEmpty } from '../utils/snowdash.js';

/**
 * Base hook for creating API hooks with state management and event handling.
 * Provides a consistent foundation for all feature-specific API hooks.
 *
 * @template TState - The shape of the state object
 * @template TEvents - Union type of event names (e.g., 'email:completed' | 'email:started')
 *
 * @param config - Configuration object with initial state
 * @returns Object containing state, setState, and event methods (on, off, emit)
 *
 * @example
 * ```typescript
 * type EmailState = { composeInfo: any; hasTypedContent: boolean };
 * type EmailEvents = 'email:completed' | 'email:started';
 *
 * const { state, setState, on, off, emit } = useBaseAPI<EmailState, EmailEvents>({
 * initialState: { composeInfo: null, hasTypedContent: false }
 * });
 * ```
 */
function useBaseAPI(config) {
 const [state, setState] = useState(config.initialState);
 const setPartialState = useCallback((updates) => {
 setState(prev => {
 const newState = {};
 for (const key in updates) {
 const typedKey = key;
 if (!isEqual(prev[typedKey], updates[typedKey])) {
 newState[typedKey] = updates[typedKey];
 }
 }
 if (!isEmpty(newState)) {
 return { ...prev, ...newState };
 }
 return prev;
 });
 }, [setState]);
 const eventHandlers = useRef(new Map());
 /**
 * Register an event handler for a specific event type
 */
 const on = useCallback((eventType, handler) => {
 if (!eventHandlers.current.has(eventType)) {
 eventHandlers.current.set(eventType, new Set());
 }
 eventHandlers.current.get(eventType).add(handler);
 }, []);
 /**
 * Unregister an event handler for a specific event type
 */
 const off = useCallback((eventType, handler) => {
 const handlers = eventHandlers.current.get(eventType);
 if (handlers) {
 handlers.delete(handler);
 if (handlers.size === 0) {
 eventHandlers.current.delete(eventType);
 }
 }
 }, []);
 /**
 * Emit an event to all registered handlers
 */
 const emit = useCallback((eventType, data) => {
 const handlers = eventHandlers.current.get(eventType);
 if (handlers) {
 handlers.forEach(handler => {
 try {
