","import React from "react";
import { NowRecordListConnected } from "@servicenow/react-components/NowRecordListConnected";

const ExperimentList = () => {
 const handleRowClicked = (event: CustomEvent) => {
 const sysId = event.detail?.payload?.sys_id;
 if (sysId) {
 window.location.href =
 "/nav_to.do?uri=x_184699_ai_expe_0_experiment.do?sys_id=" + sysId;
 }
 };

 const handleNewActionClicked = () => {
 window.location.href =
 "/nav_to.do?uri=x_184699_ai_expe_0_experiment.do?sys_id=-1";
 };

 return (
 <div className="experiment-list-section">
 <NowRecordListConnected
 table="x_184699_ai_expe_0_experiment"
 listTitle="Active Experiments"
 columns="number,name,status,owner,team,start_date,end_date"
 key="status=running^ORstatus=draft"
 onRowClicked={handleRowClicked}
 onNewActionClicked={handleNewActionClicked}
 />
 </div>
 );
};

export default ExperimentList;
",".homepage {
 max-width: 1200px;
 margin: 0 auto;
 padding: var(--now-scalable-space--lg, 24px) var(--now-scalable-space--md, 16px);
}

.homepage-title {
 font-size: var(--now-font-size--2xl, 1.75rem);
 font-weight: 700;
 color: rgb(var(--now-color--text--primary, 22, 27, 28));
 margin: 0 0 var(--now-scalable-space--lg, 24px) 0;
}

.stats-grid {
 display: grid;
 grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
 gap: var(--now-scalable-space--lg, 24px);
}

.stat-value {
 font-size: 2.5rem;
 font-weight: 700;
 color: rgb(var(--now-color--text--primary, 22, 27, 28));
 display: block;
 padding: var(--now-scalable-space--sm, 8px) var(--now-scalable-space--md, 16px);
}

.stat-label {
 font-size: var(--now-font-size--sm, 0.875rem);
 color: rgb(var(--now-color--text--secondary, 72, 79, 84));
}

.experiment-list-section {
 margin-top: var(--now-scalable-space--xl, 32px);
}

.loading-text {
 color: rgb(var(--now-color--text--secondary, 72, 79, 84));
 padding: var(--now-scalable-space--md, 16px) 0;
}
","export default function insertStyle(css, tagName = "style") {
 if (!css || typeof window === "undefined")
 return;
 if (tagName === "style") {
 const style = document.createElement("style");
 style.setAttribute("type", "text/css");
 style.innerHTML = css;
 document.head.appendChild(style);
 }
 else if (tagName === "link") {
 const link = document.createElement("link");
 link.setAttribute("rel", "stylesheet");
 link.setAttribute("href", css);
 document.head.appendChild(link);
 }
 return css;
}","import React from "react";
